/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_unicode_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`zooadmin`@`%`*/ /*!50003 TRIGGER `trg_hours_request_resolved` AFTER UPDATE ON `hours_requests` FOR EACH ROW BEGIN
    IF OLD.status = 'pending' AND NEW.status <> 'pending' THEN
        UPDATE notifications
           SET is_resolved = 1
         WHERE target_type = 'hours_request'
           AND target_id   = NEW.request_id;
    END IF;
END */;;
DELIMITER ;
