/*!50003 SET collation_connection  = utf8mb4_unicode_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`zooadmin`@`%`*/ /*!50003 TRIGGER `trg_op_supplies_restocked_resolved` AFTER UPDATE ON `operational_supplies` FOR EACH ROW BEGIN
    IF NEW.stock_count >  NEW.restock_threshold
       AND OLD.stock_count <= OLD.restock_threshold THEN
        UPDATE notifications
           SET is_resolved = 1
         WHERE target_type = 'operational_supply'
           AND target_id   = NEW.supply_id
           AND notification_type = 'low_stock';
    END IF;
END */;;
DELIMITER ;
