/*!50003 SET sql_mode              = 'IGNORE_SPACE,ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`zooadmin`@`%`*/ /*!50003 TRIGGER `trg_supply_request_resolved` AFTER UPDATE ON `supply_requests` FOR EACH ROW BEGIN
    IF OLD.status = 'pending' AND NEW.status <> 'pending' THEN
        UPDATE notifications
           SET is_resolved = 1
         WHERE target_type = 'supply_request'
           AND target_id   = NEW.request_id;
    END IF;
END */;;
DELIMITER ;
